args.sqlite_command:
WITH eq_per_haus AS (
  SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
  FROM J09C_temp
  GROUP BY HAUS
)
UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HAUS IN (
  SELECT HAUS FROM eq_per_haus WHERE eq_count >= 3
);

